// CVA SOAP endpoint — búsqueda via REST alternativo (si disponible)
// o via el endpoint SOAP de CVA
const productos=$('Parsear Input').first().json.productos||[];
const usuario=$vars.CVA_USUARIO;
const password=$vars.CVA_PASSWORD;
const allResults=[];

for(const p of productos){
  try{
    // CVA REST endpoint (documentación: grupocva.com/api/docs)
    const resp=await $helpers.httpRequest({
      method:'GET',
      url:'https://www.grupocva.com/api/v1/productos/buscar',
      headers:{'Content-Type':'application/json'},
      qs:{usuario,password,q:p.searchQuery,limite:5}
    });
    const items=resp.productos||resp.data||[];
    for(const item of (Array.isArray(items)?items:[]).slice(0,3)){
      allResults.push({mayorista:'CVA',sku:item.clave||item.codigo||'',skuFabricante:item.numero_parte||'',descripcion:item.descripcion||item.nombre||'',marca:item.marca||p.marca,precio:Number(item.precio||0),moneda:'MXN',existencia:Number(item.existencia||0),disponible:(item.existencia||0)>0,imagenUrl:item.imagen||'',productoBuscado:p.searchQuery});
    }
  }catch(e){allResults.push({mayorista:'CVA',error:e.message,productoBuscado:p.searchQuery});}
}
return allResults.map(r=>({json:r}));
